<script setup>
import { ref, onMounted, onUnmounted, watch, watchEffect } from 'vue'

const data = ref(null)
const searchTerm = ref('')
const results = ref([])

// onMounted — fetch data
onMounted(async () => {
  const res = await fetch('/api/items')
  data.value = await res.json()
  console.log('Data loaded:', data.value.length, 'items')
})

// Cleanup
let interval = setInterval(() => console.log('heartbeat'), 1000)
onUnmounted(() => clearInterval(interval))

// watch — specific ref
watch(searchTerm, async (term) => {
  if (term.length > 2) {
    const res = await fetch(`/api/search?q=${term}`)
    results.value = await res.json()
  } else {
    results.value = []
  }
})

// watchEffect — auto-tracks dependencies
watchEffect(() => {
  console.log(`Searching: ${searchTerm.value}, found: ${results.value.length}`)
})
</script>

<template>
  <input v-model="searchTerm" placeholder="Search..." />
  <ul><li v-for="r in results" :key="r.id">{{ r.name }}</li></ul>
</template>
