  { path: '/', name: 'Home', component: Home },
  { path: '/about', name: 'About', component: () => import('../views/About.vue') },  // lazy
  {
    path: '/user/:id',
    name: 'User',
    component: () => import('../views/User.vue'),
    props: true,  // pass :id as prop
    children: [
      { path: 'profile', component: () => import('../views/UserProfile.vue') },
      { path: 'settings', component: () => import('../views/UserSettings.vue') }
    ]
  }
]

const router = createRouter({ history: createWebHistory(), routes })

router.beforeEach((to, from) => {
  if (to.meta.requiresAuth && !isAuthenticated()) return { name: 'Login' }
})

export default router
