<!-- Complete solution: Shopping cart with Pinia store -->
<script setup>
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

// Pinia store
type CartItem = { id: number; name: string; price: number; qty: number }

export const useCartStore = defineStore('cart', () => {
  const items = ref<CartItem[]>([])

  const totalItems = computed(() => items.value.reduce((sum, i) => sum + i.qty, 0))
  const totalPrice = computed(() => items.value.reduce((sum, i) => sum + i.price * i.qty, 0))

  function add(product: { id: number; name: string; price: number }) {
    const existing = items.value.find(i => i.id === product.id)
    if (existing) {
      existing.qty++
    } else {
      items.value.push({ ...product, qty: 1 })
    }
  }

  function remove(id: number) {
    items.value = items.value.filter(i => i.id !== id)
  }

  function updateQty(id: number, qty: number) {
    const item = items.value.find(i => i.id === id)
    if (item) item.qty = Math.max(0, qty)
    if (item && item.qty === 0) remove(id)
  }

  return { items, totalItems, totalPrice, add, remove, updateQty }
})

// Component using the store
import { useCartStore } from '../stores/cart'
import { storeToRefs } from 'pinia'

const cart = useCartStore()
const { items, totalItems, totalPrice } = storeToRefs(cart)
</script>

<template>
  <div>
    <h2>Cart ({{ totalItems }} items)</h2>
    <div v-for="item in items" :key="item.id">
      {{ item.name }} - ${{ item.price }} x {{ item.qty }}
      <button @click="cart.updateQty(item.id, item.qty + 1)">+</button>
      <button @click="cart.updateQty(item.id, item.qty - 1)">-</button>
      <button @click="cart.remove(item.id)">Remove</button>
    </div>
    <p>Total: ${{ totalPrice.toFixed(2) }}</p>
  </div>
</template>
